mapper.select:
   select cart.*,goods.name as goodsName,goods.num as goodsNum,goods.price as goodsPrice,shopkeeper.shop_name as shopName
   from cart
   left join goods on goods.id=cart.goods_id
   left join  shopkeeper on shopkeeper.id=goods.shopkeeper_id


           and num = #{num}


           and user_id = #{userId}


           and goods_id = #{goodsId}


           and shopkeeper_id = #{shopkeeperId}


order by cart.id desc

select cart.*
from cart
where goods_id = #{goodsId} and user_id=#{userId}
